import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixel-art-error';
import { pixelArtImageModelOptionsSchema } from './pixel-art-image-options';
import { PixelArtImageModelId } from './pixel-art-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Response schema for the PixelArt /images/generate endpoint.
// Each image is returned as a base64-encoded string in `b64_json`.
const pixelArtImageResponseSchema = z.object({
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  created: z.number(),
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * The PixelArt API supports generating up to 4 images per request.
   */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers: requestHeaders,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // The PixelArt API does not accept an aspect ratio — callers must use
    // the `size` parameter (e.g. "512x512") to control output dimensions.
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'The PixelArt API does not support aspect ratios. ' +
          'Use the `size` parameter (e.g. "512x512") instead.',
      });
    }

    // Parse and validate PixelArt-specific provider options.
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Build the request body, including only defined fields.
    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      body.size = size;
    }

    if (seed != null) {
      body.seed = seed;
    }

    // Map camelCase provider options to the snake_case fields the API expects.
    if (pixelArtOptions?.style != null) {
      body.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      body.pixel_density = pixelArtOptions.pixelDensity;
    }

    if (pixelArtOptions?.outputFormat != null) {
      body.output_format = pixelArtOptions.outputFormat;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        requestHeaders,
      ),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      // Return images as base64 strings — the GeneratedFile layer in the
      // `ai` package will lazily convert them to Uint8Array when needed.
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created,
        },
      },
    };
  }
}

