  NoSuchModelError,
  type ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixel-art-image-model';
import { type PixelArtImageModelId } from './pixel-art-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /**
   * API key for the PixelArt service.
   * Defaults to the `PIXELART_API_KEY` environment variable when not provided.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Additional HTTP headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful for testing or request proxying.
   */
  fetch?: FetchFunction;
}

/**
 * PixelArt provider interface.
 *
 * PixelArt is an image-only provider — calls to `languageModel` or
 * `embeddingModel` always throw `NoSuchModelError`.
 */
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Returns an `ImageModelV3` instance for the given model ID.
   * Shorthand alias for `imageModel`.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Returns an `ImageModelV3` instance for the given model ID.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Not supported — PixelArt is an image-only provider.
   * Always throws `NoSuchModelError`.
   */
  textEmbeddingModel(modelId: string): never;
}

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

function loadPixelArtApiKey({
  apiKey,
}: {
  apiKey: string | undefined;
}): string {
  if (typeof apiKey === 'string') {
    return apiKey;
  }

  if (apiKey != null) {
    throw new Error('PixelArt API key must be a string.');
  }

  if (typeof process === 'undefined') {
    throw new Error(
      'PixelArt API key is missing. Pass it using the `apiKey` parameter. ' +
        'Environment variables are not supported in this environment.',
    );
  }

  const envApiKey = process.env['PIXELART_API_KEY'];

  if (envApiKey == null) {
    throw new Error(
      'PixelArt API key is missing. Pass it using the `apiKey` parameter or ' +
        'set the PIXELART_API_KEY environment variable.',
    );
  }

  if (typeof envApiKey !== 'string') {
    throw new Error(
      'PixelArt API key must be a string. ' +
        'The PIXELART_API_KEY environment variable is not a string.',
    );
  }

  return envApiKey;
}

/**
 * Creates a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixel-art';
 * import { generateImage } from 'ai';
 *
 * const pixelArt = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { image } = await generateImage({
 *   model: pixelArt.image('pixelart-v1'),
 *   prompt: 'A pixelated castle at sunset',
 *   providerOptions: {
 *     pixelart: { style: 'pixel', pixelDensity: 16 },
 *   },
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);

  // Headers are resolved lazily so that missing API keys only surface when
  // a request is actually made, not at provider construction time.
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadPixelArtApiKey({ apiKey: options.apiKey })}`,
        ...options.headers,
      },
      `ai-sdk/pixel-art/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId): ImageModelV3 =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? DEFAULT_BASE_URL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const unsupportedEmbeddingModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3' as const,

    // Image generation — the only capability this provider supports.
    image: createImageModel,
    imageModel: createImageModel,

    // Unsupported model types — PixelArt is an image-only provider.
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: unsupportedEmbeddingModel,
    textEmbeddingModel: unsupportedEmbeddingModel,
  };
}

/**
 * Default PixelArt provider instance.
 * Uses `PIXELART_API_KEY` from the environment.
 */
export const pixelArt = createPixelArt();

