// Minimal valid API response — one base64 image.
const BASIC_RESPONSE = {
  images: [{ b64_json: 'aGVsbG8=' }],
  created: 1700000000,
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [TEST_ENDPOINT]: {
      response: {
        type: 'json-value',
        body: BASIC_RESPONSE,
      },
    },
  });

  // -------------------------------------------------------------------------
  // Constructor
  // -------------------------------------------------------------------------

  describe('constructor', () => {
    it('exposes correct provider and model metadata', () => {
      const model = createBasicModel();

      expect(model.specificationVersion).toBe('v3');
      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  // -------------------------------------------------------------------------
  // Request body construction
  // -------------------------------------------------------------------------

  describe('doGenerate – request body', () => {
    it('includes prompt, n, size, and seed in the request body', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
      });
    });

    it('omits size and seed when they are undefined', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
      });
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
    });

    it('maps style provider option to API body field', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        style: 'retro',
      });
    });

    it('maps pixelDensity to pixel_density in request body', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { pixelDensity: 8 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '256x256',
        pixel_density: 8,
      });
    });

    it('maps outputFormat to output_format in request body', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { outputFormat: 'jpeg' } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        output_format: 'jpeg',
      });
    });

    it('maps all three provider options simultaneously', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: 7,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelart: { style: '8bit', pixelDensity: 16, outputFormat: 'png' },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '1024x1024',
        seed: 7,
        style: '8bit',
        pixel_density: 16,
        output_format: 'png',
      });
    });

    it('forwards custom request headers', async () => {
      await createBasicModel({
        headers: { 'x-provider-header': 'provider-value' },
      }).doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: { 'x-request-header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
        'content-type': 'application/json',
      });
    });
  });

  // -------------------------------------------------------------------------
  // Warnings
  // -------------------------------------------------------------------------

  describe('doGenerate – warnings', () => {
    it('emits an unsupported warning when aspectRatio is provided', async () => {
      const result = await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    });

    it('emits no warnings when no unsupported features are used', async () => {
      const result = await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { style: 'pixel' } },
      });

      expect(result.warnings).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Response parsing
  // -------------------------------------------------------------------------

  describe('doGenerate – response', () => {
    it('returns base64 image strings from the API response', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: {
          images: [
            { b64_json: 'Zmlyc3Q=' },
            { b64_json: 'c2Vjb25k' },
          ],
          created: 1700000001,
        },
      };

      const result = await createBasicModel().doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe('Zmlyc3Q=');
      expect(result.images[1]).toBe('c2Vjb25k');
    });

    it('includes timestamp, modelId, and headers in the response object', async () => {
      const testDate = new Date('2024-06-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-v1',
        headers: expect.any(Object),
      });
    });

    it('surfaces the created timestamp in providerMetadata', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'json-value',
        body: { images: [{ b64_json: 'dGVzdA==' }], created: 1700099999 },
      };

      const result = await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelart: { created: 1700099999 },
      });
    });
  });

  // -------------------------------------------------------------------------
  // Error handling
  // -------------------------------------------------------------------------

  describe('doGenerate – error handling', () => {
    it('throws on a 400 API error response', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt: prompt must not be empty',
            type: 'invalid_request_error',
          },
        }),
      };

      await expect(
        createBasicModel().doGenerate({
          prompt: '',
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          files: undefined,
          mask: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt: prompt must not be empty',
        statusCode: 400,
      });
    });

    it('throws on a 401 authentication error', async () => {
      server.urls[TEST_ENDPOINT].response = {
        type: 'error',
        status: 401,
        body: JSON.stringify({
          error: { message: 'Unauthorized: invalid API key', code: '401' },
        }),
      };

      await expect(
        createBasicModel().doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          files: undefined,
          mask: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        statusCode: 401,
      });
    });
  });
});

