    it('provider.imageModel() returns a PixelArtImageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-pro');

      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(model.modelId).toBe('pixelart-pro');
    });

    it('image() and imageModel() return equivalent models', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      const a = provider.image('pixelart-retro');
      const b = provider.imageModel('pixelart-retro');

      expect(a.modelId).toBe(b.modelId);
      expect(a.provider).toBe(b.provider);
      expect(a.specificationVersion).toBe(b.specificationVersion);
    });

    it('accepts an arbitrary model ID via the open-ended union', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-custom-future-model');

      expect(model.modelId).toBe('pixelart-custom-future-model');
    });
  });

  describe('unsupported model types', () => {
    it('languageModel() throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });

    it('embeddingModel() throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.embeddingModel('text-embedding-3')).toThrow(
        NoSuchModelError,
      );
    });

    it('textEmbeddingModel() throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.textEmbeddingModel('embed-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('custom baseURL', () => {
    it('honours a custom baseURL passed in settings', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://my-proxy.example.com/pixelart/v2',
      });
      // We can't directly inspect the URL from the provider object, but we can
      // verify the model is created successfully and carries the right identity.
      const model = provider.image('pixelart-v1');
      expect(model.modelId).toBe('pixelart-v1');
    });

    it('strips a trailing slash from baseURL', () => {
      // withoutTrailingSlash is used internally; creating a model should not
      // throw or produce double slashes.
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://api.pixelart.ai/v1/',
      });
      expect(provider.image('pixelart-v1')).toBeDefined();
    });
  });

  describe('API key loading', () => {
    it('uses PIXELART_API_KEY env var when no apiKey option is given', () => {
      const originalKey = process.env['PIXELART_API_KEY'];

      try {
        process.env['PIXELART_API_KEY'] = 'env-test-key';
        // Provider construction itself is safe; key is only loaded lazily.
        const provider = createPixelArt();
        expect(provider.specificationVersion).toBe('v3');
      } finally {
        if (originalKey === undefined) {
          delete process.env['PIXELART_API_KEY'];
        } else {
          process.env['PIXELART_API_KEY'] = originalKey;
        }
      }
    });
  });
});

describe('pixelArt (default export)', () => {
  it('is a PixelArtProvider with specificationVersion v3', () => {
    // The default instance is created without options; construction itself
    // is safe because API key resolution is deferred to request time.
    expect(pixelArt).toBeDefined();
    expect(pixelArt.specificationVersion).toBe('v3');
  });
});
